<?php
namespace App\Domain\Characters\Templates;
use App\Domain\Media\CharacterVisuals\CharacterVisualAssetService;use App\Domain\Media\MediaAssetType;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\CharacterClass;use App\Models\CharacterTemplate;
final class CharacterTemplateReadService{private $visuals;public function __construct(CharacterVisualAssetService $visuals){$this->visuals=$visuals;}public function adminList(array $filters){$q=$this->query()->withCount('characters');foreach(['status','body_type','character_class_id','presentation_gender']as$f)if(isset($filters[$f])&&$filters[$f]!=='')$q->where($f,$filters[$f]);$p=$q->orderBy('sort_order')->orderBy('name')->paginate(25)->appends($filters);$p->setCollection($p->getCollection()->map(function($t){return$this->row($t);}));return$p;}public function available(){return$this->query()->where('status',CatalogStatus::ACTIVE)->whereIn('presentation_gender',CharacterTemplatePresentationGender::all())->whereHas('characterClass',function($q){$q->where('status',CatalogStatus::ACTIVE);})->orderBy('sort_order')->orderBy('name')->get()->map(function($t){return$this->row($t);})->filter(function($row){return$row['visual']->exists();})->values();}public function creationOptions(){$templates=$this->available();$groups=[];foreach($templates as$row){$class=$row['model']->characterClass;$gender=$row['model']->presentation_gender;if(!isset($groups[$class->id]))$groups[$class->id]=['id'=>$class->id,'name'=>$class->name,'genders'=>[]];if(!isset($groups[$class->id]['genders'][$gender]))$groups[$class->id]['genders'][$gender]=['code'=>$gender,'label'=>CharacterTemplatePresentationGender::labels()[$gender],'templates'=>[]];$groups[$class->id]['genders'][$gender]['templates'][]=$row;}return['templateGroups'=>array_values($groups),'templates'=>$templates,'genderLabels'=>CharacterTemplatePresentationGender::labels()];}public function detail(CharacterTemplate $t){$t->loadMissing(['characterClass','mediaAssets'=>function($q){$q->where('asset_type',MediaAssetType::BASE_VISUAL)->where('is_primary',true);}]);$t->loadCount('characters');return$this->row($t);}public function options(){return['classes'=>CharacterClass::orderBy('sort_order')->orderBy('name')->get(),'statuses'=>CatalogStatus::values(),'genders'=>CharacterTemplatePresentationGender::labels(),'body_types'=>CharacterTemplate::select('body_type')->distinct()->orderBy('body_type')->pluck('body_type')];}private function query(){return CharacterTemplate::with(['characterClass','mediaAssets'=>function($q){$q->where('asset_type',MediaAssetType::BASE_VISUAL)->where('is_primary',true);}]);}private function row($t){$labels=CharacterTemplatePresentationGender::labels();return['model'=>$t,'visual'=>$this->visuals->presentation($t),'class_available'=>$t->characterClass&&$t->characterClass->status===CatalogStatus::ACTIVE,'presentation_label'=>isset($labels[$t->presentation_gender])?$labels[$t->presentation_gender]:'Sin configurar'];}}
